parameters.jsCode:
const changes = $input.all();
if (changes.length === 0) {
  return [{ json: { summary: 'No significant price changes this week.' } }];
}
// Format changes into a readable list
const lines = changes.map(item => {
  const c = item.json;
  return `- ${c.title} (${c.competitor}): ${c.prev_price} → ${c.price} (${c.pct_change}%)`;
}).join('\n');
return [{
  json: {
    prompt: `Summarize the following competitive intelligence price changes in a professional tone for a business report:\n\n${lines}`
  }
}];

