const response = $json;
let summary = 'Unable to generate summary.';
if (response.choices && response.choices[0] && response.choices[0].message) {
  summary = response.choices[0].message.content.trim();
}
return [{
  json: {
    subject: 'Weekly Competitive Intelligence Report',
    text: `Here is your weekly summary of significant price changes:\n\n${summary}`
  }
}];

// Log any errors
console.error('Weekly summary error:', $json.error);
return [];
